dleplugin.phpinstall:
global $db;
$db->query("CREATE TABLE IF NOT EXISTS " . PREFIX . "_mcp_tokens (id INT(11) NOT NULL AUTO_INCREMENT, token VARCHAR(64) NOT NULL DEFAULT '', label VARCHAR(100) NOT NULL DEFAULT '', created_at INT(11) NOT NULL DEFAULT 0, last_used INT(11) NOT NULL DEFAULT 0, active TINYINT(1) NOT NULL DEFAULT 1, PRIMARY KEY (id), UNIQUE KEY token (token)) ENGINE=InnoDB DEFAULT CHARACTER SET " . COLLATE . " COLLATE " . COLLATE . "_general_ci");
$db->query("CREATE TABLE IF NOT EXISTS " . PREFIX . "_mcp_logs (id INT(11) NOT NULL AUTO_INCREMENT, token_id INT(11) NOT NULL DEFAULT 0, tool VARCHAR(100) NOT NULL DEFAULT '', params TEXT NOT NULL, response_status VARCHAR(20) NOT NULL DEFAULT 'ok', ip VARCHAR(45) NOT NULL DEFAULT '', created_at INT(11) NOT NULL DEFAULT 0, PRIMARY KEY (id), KEY token_id (token_id), KEY created_at (created_at)) ENGINE=InnoDB DEFAULT CHARACTER SET " . COLLATE . " COLLATE " . COLLATE . "_general_ci");
$db->query("CREATE TABLE IF NOT EXISTS " . PREFIX . "_mcp_settings (id INT(11) NOT NULL AUTO_INCREMENT, server_enabled TINYINT(1) NOT NULL DEFAULT 1, disabled_tools TEXT NOT NULL DEFAULT '', updated_at INT(11) NOT NULL DEFAULT 0, PRIMARY KEY (id)) ENGINE=InnoDB DEFAULT CHARACTER SET " . COLLATE . " COLLATE " . COLLATE . "_general_ci");
$check = $db->super_query("SELECT COUNT(*) as c FROM " . PREFIX . "_mcp_settings");
if ($check['c'] == 0) {
    $db->query("INSERT INTO " . PREFIX . "_mcp_settings (server_enabled, disabled_tools, updated_at) VALUES (1, '', " . time() . ")");
}

dleplugin.phpdelete:
global $db;
$db->query("DROP TABLE IF EXISTS " . PREFIX . "_mcp_tokens");
$db->query("DROP TABLE IF EXISTS " . PREFIX . "_mcp_logs");
$db->query("DROP TABLE IF EXISTS " . PREFIX . "_mcp_settings");
